const headers = $json.headers ?? {};
const body = $json.body ?? $json;
const expectedToken = 'dev-internal-token';
const hmacSecret = 'dev-hmac-secret';

function getHeader(name) {
  const lowerName = name.toLowerCase();
  const found = Object.entries(headers).find(([key]) => key.toLowerCase() === lowerName);
  return found?.[1];
}

async function hmacSha256Hex(secret, message) {
  const encoder = new TextEncoder();
  const key = await crypto.subtle.importKey('raw', encoder.encode(secret), { name: 'HMAC', hash: 'SHA-256' }, false, ['sign']);
  const signature = await crypto.subtle.sign('HMAC', key, encoder.encode(message));
  return Array.from(new Uint8Array(signature)).map((byte) => byte.toString(16).padStart(2, '0')).join('');
}

const authorization = String(getHeader('authorization') ?? '');
const bearerToken = authorization.replace(/^Bearer\s+/i, '').trim();
const automationToken = String(getHeader('x-automation-token') ?? '');
const signature = String(getHeader('x-hub-signature-256') ?? getHeader('x-signature') ?? '');
let verified = false;

if (signature && body.rawBody) {
  const expectedSignature = `sha256=${await hmacSha256Hex(hmacSecret, body.rawBody)}`;
  verified = signature === expectedSignature;
}

if (!verified) {
  verified = bearerToken === expectedToken || automationToken === expectedToken;
}

if (!verified) {
  throw new Error('Invalid automation signature or token');
}

const event = { ...body };
if (!event.eventId || !event.eventType || !event.reservationId) {
  throw new Error('Missing required reservation automation event fields');
}
if (!['reservation.created', 'reservation.updated'].includes(event.eventType)) {
  throw new Error(`Unsupported reservation event type: ${event.eventType}`);
}

return {
  json: {
    backendBaseUrl: 'http://host.docker.internal:3000/api/v1',
    internalToken: expectedToken,
    source: 'n8n-uc13-reservation-created-automation',
    smtpFrom: 'hotel-management@example.com',
    event,
  },
};

const context = $json.data ?? $json;
const reservation = context.reservation ?? context;
const customer = context.customer ?? reservation.customer ?? {};
const room = context.room ?? reservation.room ?? {};
const currency = context.currency ?? 'VND';
const totalAmount = reservation.totalAmount ?? reservation.totalPrice ?? reservation.amount ?? 0;
const reservationCode = reservation.code ?? reservation.reservationCode ?? reservation.id;
const checkInAt = reservation.checkInAt ?? reservation.checkinAt ?? reservation.startDate;
const checkOutAt = reservation.checkOutAt ?? reservation.checkoutAt ?? reservation.endDate;
const html = `
  <h2>Xac nhan dat phong ${reservationCode}</h2>
  <p>Xin chao ${customer.fullName ?? customer.name ?? 'Quy khach'},</p>
  <p>Dat phong cua quy khach da duoc ghi nhan thanh cong.</p>
  <table border="1" cellpadding="8" cellspacing="0">
    <tr><td>Ma dat phong</td><td>${reservationCode}</td></tr>
    <tr><td>Loai/phong</td><td>${room.roomTypeName ?? room.typeName ?? room.name ?? 'Dang cap nhat'}</td></tr>
    <tr><td>Thoi gian nhan phong</td><td>${checkInAt ?? 'Dang cap nhat'}</td></tr>
    <tr><td>Thoi gian tra phong</td><td>${checkOutAt ?? 'Dang cap nhat'}</td></tr>
    <tr><td>Tong gia tri</td><td>${Number(totalAmount).toLocaleString('vi-VN')} ${currency}</td></tr>
  </table>
`;
return {
  json: {
    ...context,
    email: {
      from: $('Validate HMAC or Token').item.json.smtpFrom,
      to: customer.email,
      subject: `Xac nhan dat phong ${reservationCode}`,
      html,
    },
  },
};

const context = $('Get Reservation Automation Context').item.json.data ?? $('Get Reservation Automation Context').item.json;
const reservation = context.reservation ?? context;
const customer = context.customer ?? reservation.customer ?? {};
const directCheckIn = context.directCheckIn ?? {};
const guideUrl = directCheckIn.guideUrl ?? context.directCheckInGuideUrl ?? `${$('Validate HMAC or Token').item.json.backendBaseUrl.replace('/api/v1', '')}/direct-check-in/${reservation.id}`;
const requiredDocuments = directCheckIn.requiredDocuments ?? ['CCCD/Ho chieu', 'Ma dat phong', 'Thong tin lien he'];
const html = `
  <h2>Huong dan Direct Check-in</h2>
  <p>Xin chao ${customer.fullName ?? customer.name ?? 'Quy khach'},</p>
  <p>Quy khach co the tu check-in qua duong dan sau:</p>
  <p><a href="${guideUrl}">${guideUrl}</a></p>
  <p>Giay to can chuan bi:</p>
  <ul>${requiredDocuments.map((item) => `<li>${item}</li>`).join('')}</ul>
`;
return {
  json: {
    email: {
      from: $('Validate HMAC or Token').item.json.smtpFrom,
      to: customer.email,
      subject: `Huong dan Direct Check-in - ${reservation.code ?? reservation.id}`,
      html,
    },
  },
};

const context = $('Get Reservation Automation Context').item.json.data ?? $('Get Reservation Automation Context').item.json;
const reservation = context.reservation ?? context;
return {
  json: {
    source: 'n8n-uc13-reservation-created-automation',
    reservationId: reservation.id ?? $('Validate HMAC or Token').item.json.event.reservationId,
    reminderJobs: [
      {
        recipientType: 'CUSTOMER',
        channel: 'EMAIL_SMS',
        templateCode: 'CHECK_IN_REMINDER_24H',
        sendBeforeHours: 24,
      },
      {
        recipientType: 'RECEPTION',
        channel: 'INTERNAL_NOTIFICATION',
        templateCode: 'RECEPTION_CHECK_IN_READY_1H',
        sendBeforeHours: 1,
      }
    ],
  },
};

const reminderResult = $json.data ?? $json;
const context = $('Get Reservation Automation Context').item.json.data ?? $('Get Reservation Automation Context').item.json;
const housekeepingResult = $('Create Housekeeping Task').item.json.data ?? $('Create Housekeeping Task').item.json;
return {
  json: {
    ok: true,
    workflow: 'uc13-reservation-created-automation',
    reservationId: context.reservation?.id ?? context.id,
    confirmationEmailSent: true,
    housekeepingTask: housekeepingResult,
    reminderJobs: reminderResult,
  },
};
